def _check_cron_inline(
    a: AddedLine,
    text: str,
) -> tuple[str, int, str, str] | None:
    """Check a cron line for missing log redirect."""
    stripped = text.rstrip()
    if not stripped:
        return None
    if CRON_SHEBANG_OR_COMMENT.match(stripped):
        return None
    if CRON_ENV.match(stripped):
        return None
    if not CRON_LINE.match(stripped):
        return None
    if not CRON_OK.search(stripped):
        return (a.path, a.lineno, "cron-no-log-redirect", stripped)
    return None

def detect_python_multiline(
    added: list[AddedLine],
) -> Iterator[tuple[AddedLine, str]]:
    """Detect except-header followed by sole-statement body in added lines."""

    by_file: dict[str, dict[int, AddedLine]] = {}
    for a in added:
        if not is_python_file(a.path):
            continue
        by_file.setdefault(a.path, {})[a.lineno] = a

    for lines in by_file.values():
        for lineno, header in sorted(lines.items()):
            m = PY_EXCEPT_HEADER.match(header.text)
            if not m:
                continue
            if "KeyboardInterrupt" in header.text:
                continue
            header_indent = len(m.group("indent"))
            nxt, pid = _resolve_next_line(lines, lineno, header_indent)
            if pid is not None:
                yield header, pid
                continue
            if nxt is None:
                continue
            pid = _classify_except_body(nxt, lines, lineno, header_indent)
            if pid is None:
                continue
            yield header, pid

def detect_js_multiline(
    added: list[AddedLine],
) -> Iterator[tuple[AddedLine, str]]:
    """Detect catch-header followed by silent return in added lines."""

    by_file: dict[str, dict[int, AddedLine]] = {}
    for a in added:
        if not is_js_file(a.path):
            continue
        by_file.setdefault(a.path, {})[a.lineno] = a

    for lines in by_file.values():
        for lineno, header in sorted(lines.items()):
            m = JS_CATCH_HEADER.match(header.text)
            if not m:
                continue
            header_indent = len(m.group("indent"))
            if _check_catch_body(lines, lineno, header_indent):
                yield header, "js-catch-silent-return-multi"

def detect_ansible_tasks(added_lines):
    """Multi-line detector: find shell/command tasks without register:.

    Returns list of (header_addedline, pattern_id).
    """
    violations = []
    lines = added_lines
    i = 0
    while i < len(lines):
        line = lines[i]
        text = line.text

        if _SHELL_RE.search(text) or _COMMAND_RE.search(text):
            has_register, has_failed_when = _scan_task_flags(lines, i)
            if not has_register and not has_failed_when:
                if _check_changed_when_false(lines, i):
                    violations.append((line, "ansible-shell-no-register"))
                else:
                    violations.append((line, "ansible-shell-no-guard"))

        i += 1

    return violations
